=<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>Ingreso de Comprobantes Emitidos</title>

<style>
  body {
    font-family: "Segoe UI", sans-serif;
    background: #f3f6f9;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
  }
  .form-container {
    background: white;
    padding: 35px 40px;
    border-radius: 14px;
    box-shadow: 0 5px 20px rgba(0,0,0,0.08);
    width: 400px;
    max-width: 95%;
  }
  .logo { display: flex; justify-content: center; margin-bottom: 15px; }
  .logo img { width: 110px; height: auto; }
  h2 { text-align: center; color: #911f30; margin-bottom: 25px; font-size: 20px; font-weight: 700; }
  label { display: block; margin-bottom: 6px; color: #333; font-weight: 600; }
  select, input {
    width: 100%; padding: 12px; margin-bottom: 18px; border-radius: 8px;
    border: 1px solid #ccc; font-size: 15px; background-color: #fafafa;
    box-sizing: border-box; transition: all 0.2s ease;
  }
  #cantidad { margin-bottom: 28px; }
  select:focus, input:focus {
    border-color: #911f30; background-color: #fff; outline: none; box-shadow: 0 0 5px #911f3040;
  }
  button {
    width: 100%; background-color: #911f30; color: white; border: none; padding: 12px;
    font-size: 15px; border-radius: 8px; cursor: pointer; transition: all 0.25s ease; font-weight: 600;
  }
  button:hover { background-color: #7c1a29; transform: scale(1.02); }
  .message { text-align: center; margin-top: 10px; font-weight: 600; }
  @media (max-width: 480px) { .form-container { padding: 25px 20px; } }
</style>
</head>

<body>
<div class="form-container">
  <div class="logo">
    <img src="https://apg-consulting.com/wp-content/uploads/cropped-APG-Logo-png-peque.png" alt="APG Consulting Logo">
  </div>
  <h2>Ingreso de Comprobantes Emitidos</h2>

  <form id="formulario">
    <!-- País -->
    <label for="pais">País</label>
    <select id="pais" name="pais" required>
      <option value="" disabled selected>Seleccionar País</option>
      <option value="AR">AR</option>
      <option value="BO">BO</option>
      <option value="CO">CO</option>
      <option value="CR">CR</option>
      <option value="EC">EC</option>
      <option value="ES">ES</option>
      <option value="PE">PE</option>
    </select>

    <!-- Entorno -->
    <label for="entorno">Entorno</label>
    <select id="entorno" name="entorno" required>
      <option value="">Seleccione un país primero</option>
    </select>

    <!-- Año -->
    <label for="anio">Año</label>
    <select id="anio" name="anio" required>
      <option value="">Seleccionar Año</option>
    </select>

    <!-- Mes -->
    <label for="mes">Mes</label>
    <select id="mes" name="mes" required>
      <option value="">Seleccionar Mes</option>
    </select>

    <!-- Cantidad -->
    <label for="cantidad">Cantidad de documentos</label>
    <input type="number" id="cantidad" name="cantidad" min="1" placeholder="Ej: 25" required />

    <button type="submit">Enviar</button>
    <div id="responseMsg" class="message"></div>
  </form>
</div>

<script>
document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('formulario');
  const responseMsg = document.getElementById('responseMsg');
  const paisSelect = document.getElementById('pais');
  const entornoSelect = document.getElementById('entorno');
  const anioSelect = document.getElementById('anio');
  const mesSelect = document.getElementById('mes');

  // Entornos por país
  const entornosPorPais = {
    CO: ["NESTLE", "Baker"],
    EC: ["NESTLE", "Bebemundo", "DGAC"],
    CR: ["NESTLE"]
  };

  // Función segura para llenar años y meses
function generarFechas() {
  try {
    const today = new Date();
    const currentMonth = today.getMonth(); // 0 = Enero
    const currentYear = today.getFullYear();

    const months = [];
    const yearSet = new Set();

    for (let i = 3; i >= 1; i--) {
      const d = new Date(currentYear, currentMonth - i, 1);
      const nombreMes = d.toLocaleString('es-ES', { month: 'long' });
      const valorMes = String(d.getMonth() + 1).padStart(2, '0');
      const año = d.getFullYear();

      months.push({ name: nombreMes.charAt(0).toUpperCase() + nombreMes.slice(1), value: valorMes });
      yearSet.add(año);
    }

    mesSelect.innerHTML = '<option value="">Seleccionar Mes</option>' +
      months.map(m => `<option value="${m.value}">${m.name}</option>`).join('');

    anioSelect.innerHTML = '<option value="">Seleccionar Año</option>' +
      Array.from(yearSet).sort((a, b) => a - b).map(y => `<option value="${y}">${y}</option>`).join('');
  } catch (e) {
    console.error('Error generando fechas:', e);
  }
}



  // Actualizar entornos según país
  function actualizarEntornos(pais) {
    entornoSelect.innerHTML = "";
    if (entornosPorPais[pais]) {
      const opciones = entornosPorPais[pais]
        .map(e => `<option value="${e}">${e}</option>`)
        .join('');
      entornoSelect.innerHTML = `<option value="">Seleccionar Entorno</option>${opciones}`;
    } else {
      entornoSelect.innerHTML = `<option value="">Seleccione un país válido</option>`;
    }
  }

  // Inicializar
  generarFechas();
  actualizarEntornos(""); // estado inicial

  // Listener de cambio de país
  paisSelect.addEventListener('change', (e) => {
    const pais = e.target.value;
    actualizarEntornos(pais);
  });

  // Envío del formulario
  form.addEventListener('submit', async function (e) {
    e.preventDefault();

    const btn = form.querySelector('button');
    btn.disabled = true;
    btn.innerText = 'Enviando...';
    btn.style.opacity = '0.8';
    responseMsg.textContent = '';

    const pais = paisSelect.value;
    const entorno = entornoSelect.value;
    const anio = anioSelect.value;
    const mes = mesSelect.value;
    const cantidad = document.getElementById('cantidad').value;

    if (!pais) {
      responseMsg.textContent = '⚠️ Selecciona un país';
      responseMsg.style.color = 'red';
      btn.disabled = false; btn.innerText = 'Enviar'; btn.style.opacity = '1';
      return;
    }
    if (!entorno) {
      responseMsg.textContent = '⚠️ Selecciona un entorno';
      responseMsg.style.color = 'red';
      btn.disabled = false; btn.innerText = 'Enviar'; btn.style.opacity = '1';
      return;
    }
    if (cantidad <= 0) {
      responseMsg.textContent = '⚠️ La cantidad debe ser mayor a 0';
      responseMsg.style.color = 'red';
      btn.disabled = false; btn.innerText = 'Enviar'; btn.style.opacity = '1';
      return;
    }

    const payload = { pais, entorno, anio, mes, cantidad };

    try {
      const res = await fetch('https://lilia-unshunted-morris.ngrok-free.dev/webhook/Formulario', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        responseMsg.textContent = '✅ Enviado correctamente';
        responseMsg.style.color = 'green';
        form.reset();
        actualizarEntornos(""); // volver a estado inicial
      } else {
        responseMsg.textContent = '❌ Error al enviar. Intenta de nuevo.';
        responseMsg.style.color = 'red';
      }
    } catch (err) {
      console.error('Error en el envío:', err);
      responseMsg.textContent = '⚠️ Ocurrió un error al conectar con el servidor.';
      responseMsg.style.color = 'red';
    } finally {
      btn.disabled = false;
      btn.innerText = 'Enviar';
      btn.style.opacity = '1';
    }
  });
});
</script>
</body>
</html>

